#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
const int Mod=1e9+7,N=1e5+10;int dp[N];
inline void UP(int &x){x<0?x+=Mod:0;}inline void DN(int &x){x<Mod?0:x-=Mod;}
inline int qpow(int a,int b){int r(1);while(b)b&1?r=1ll*r*a%Mod:0,a=1ll*a*a%Mod,b=b>>1;return r;}
int main()
{
	int n,k,l,r;scanf("%d%d%d%d",&n,&k,&l,&r);
	bool flag=(l<=k&&k<=r);l=(l-1)/k;r/=k;int T=r-l;
	drep(T,1,i)
	{
		int tmp=r/i-l/i;UP(dp[i]=qpow(tmp,n)-tmp);
		for(int j=i<<1;j<=T;j+=i)UP(dp[i]-=dp[j]);
	}
	printf("%d\n",dp[1]+flag);return 0;
}
